							dXLengthUm = pInspectROIRgn->m_MeasureData[iInspectionBufferIdx][iTabIdx].m_dSurfaceInspectionXLength * THEAPP.m_pCalDataService_N[VISION_NUMBER_1]->GetPixelSize();
