							sXLengthTitle.Format("%s_Img%d_RoiNo%d_InspectTab%d_%s_XLength(um)", THEAPP.m_ModelDefineInfo.m_strVisionName_Short[VISION_NUMBER_1], pInspectROIRgn->miTeachImageIndex, pInspectROIRgn->miInspectionROIID, iTabIdx + 1, THEAPP.m_strDefectName[pInspectROIRgn->m_AlgorithmParam[iTabIdx].m_iDefectType]);
							sYLengthTitle.Format("%s_Img%d_RoiNo%d_InspectTab%d_%s_YLength(um)", THEAPP.m_ModelDefineInfo.m_strVisionName_Short[VISION_NUMBER_1], pInspectROIRgn->miTeachImageIndex, pInspectROIRgn->miInspectionROIID, iTabIdx + 1, THEAPP.m_strDefectName[pInspectROIRgn->m_AlgorithmParam[iTabIdx].m_iDefectType]);

