		strLog.Format("Halcon Exception [AlgorithmThreadDefine::ResultSaveThread_N3] : <%s>%s", sOperatorName, sErrMsg);
		THEAPP.m_log_halcon->warn("{}", LOG_CSTR(strLog));

		//////////////////////////////////////////////////////////////////////////
		/// Error Processing

		pAlgorithm->ChangeInspectDone(iInspectionBufferIdx, BUFFER_STATUS_AVAILABLE);

