		strLog.Format("Halcon Exception [AlgorithmThreadDefine::ResultSaveThread_N2] : <%s>%s", sOperatorName, sErrMsg);
		THEAPP.m_log_halcon->warn("{}", LOG_CSTR(strLog));

		//////////////////////////////////////////////////////////////////////////
