					pSaveLogThreadIDParam->iPcVisionNo = iPcVisionNo;
					pSaveLogThreadIDParam->iMzNo = iMzNo;
					pSaveLogThreadIDParam->iTrayNo = iTrayNo;
					pSaveLogThreadIDParam->iModuleNo = iModuleNo;
