							GenCircleContourXld(&HCircleXLD, dInnerCircleCenterY, dInnerCircleCenterX, dInnerCircleRadius, 0, 6.28318, "positive", 1);
							GenRegionContourXld(HCircleXLD, &HFAIMeasureRgn, "filled");
							ConcatObj(pAlgorithm->m_HReviewXLD_FAI_Item[iCurInspectionBufferIdx][6][iFaiParamIndex][1], HCircleXLD, &(pAlgorithm->m_HReviewXLD_FAI_Item[iCurInspectionBufferIdx][6][iFaiParamIndex][1]));

