											ConcatObj(algo->m_HDefectRgn_MultiFocus_Ring_Particle[result.request->vision_inspection_thread_index][result.request->image_idx - 1][inspect_type - 1][defect_type], restored_region, &(algo->m_HDefectRgn_MultiFocus_Ring_Particle[result.request->vision_inspection_thread_index][result.request->image_idx - 1][inspect_type - 1][defect_type]));
