									ConcatObj(algo->m_HDefectRgn_DefectName[result.request->vision_inspection_thread_index][inspect_type - 1][defect_type], restored_region, &(algo->m_HDefectRgn_DefectName[result.request->vision_inspection_thread_index][inspect_type - 1][defect_type]));
