							TransFromRgb(pAlgorithm->m_HInspectCImage[iCurInspectionBufferIdx][CHANNEL_TYPE_R][i], pAlgorithm->m_HInspectCImage[iCurInspectionBufferIdx][CHANNEL_TYPE_G][i], pAlgorithm->m_HInspectCImage[iCurInspectionBufferIdx][CHANNEL_TYPE_B][i],
										 &(pAlgorithm->m_HInspectCImage[iCurInspectionBufferIdx][CHANNEL_TYPE_H][i]), &(pAlgorithm->m_HInspectCImage[iCurInspectionBufferIdx][CHANNEL_TYPE_S][i]), &(pAlgorithm->m_HInspectCImage[iCurInspectionBufferIdx][CHANNEL_TYPE_I][i]), "hsi");

