												pAlgorithm->InspectAVI(iCurInspectionBufferIdx, iCurThreadIdx, pInspectROIRgn, iTabIdx, HPreProcessImage, HROIHRegion, pInspectROIRgn->m_AlgorithmParam[iTabIdx], &HResultXLD, pAlgorithm->m_HInspectCImage[iCurInspectionBufferIdx][pInspectROIRgn->m_AlgorithmParam[iTabIdx].m_iProcessChType], pAlgorithm->m_HInspectCImage[iCurInspectionBufferIdx][pInspectROIRgn->m_AlgorithmParam[iTabIdx].m_iProcessChTypeDC][iImageIdx - 1]);
