								GenCircleContourXld(&HCircleXLD, dInnerCircleCenterY, dInnerCircleCenterX, dInnerCircleRadius, 0, 6.28318, "positive", 1);
								GenRegionContourXld(HCircleXLD, &HFAIMeasureRgn, "filled");
